python3 << 'EOF'
import re

with open('/home/archon/proj/Cech-Cohomology/blueprint/src/chapters/Cohomology_CechHigherDirectImage.tex') as f:
    content = f.read()

# Find all label occurrences and check if within the enclosing environment they have a \lean{}
# Simple approach: for each \label{...} in the chapter, check if within the next 500 chars there's \lean{
labels = [(m.start(), m.group(1)) for m in re.finditer(r'\\label\{((?:lem|def|thm):[^}]+)\}', content)]

gaps = []
for pos, label in labels:
    # Look forward up to \end{lemma} or \end{definition} or \end{theorem}
    snippet = content[pos:pos+800]
    env_end = re.search(r'\\end\{(lemma|definition|theorem|proposition|remark|corollary)\}', snippet)
    if env_end:
        block = snippet[:env_end.start()]
    else:
        block = snippet[:600]
    if '\\lean{' not in block and '\\mathlibok' not in block:
        gaps.append(label)

print(f"Nodes without \\lean{{}} or \\mathlibok: {len(gaps)}")
for g in gaps:
    print(f"  {g}")
EOF
